API_name: school_activities_news_upcoming
Description:
{
  "description": "取得全校近期即將舉辦的活動公告。",
  "required_parameters": [],
  "optional_parameters": [
    {
      "name": "days",
      "type": "NUMBER",
      "description": "往後查詢幾天內的活動",
      "default": 7
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "回傳結果上限",
      "default": 20
    }
  ]
}

